def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.zeros_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap < 0.1:
            priorities[idx] = np.inf
            continue
        base_factor = np.exp(-item / (cap + 1e-5))
        complexity_score = 0.0
        chaos_factor = 1.0
        influence = 0.0
        decay = 1.0
        cache = []
        for m in range(1, 15):
            partial = 0.0
            if cap % (m+3) == 0:
                chaos_factor *= 1.03 + 0.005 * m
            elif (cap + m) % 11 == 0:
                chaos_factor *= 0.97 - 0.007 * m
            if item < cap / (1 + m*0.2):
                partial = (np.sin(m * np.log1p(item)) + np.cos(cap / (m+1))) * chaos_factor
            else:
                partial = ((m ** 3) / (cap + m)) * np.tanh(item / (m+1)) * chaos_factor
            if m % 4 == 0:
                for n in range(1, 4):
                    val = (cap ** 1.1) / ((item + n) ** 0.9 + 1)
                    val *= np.sin(val + m * n)
                    influence += val if (cap - item * n) % (m + n + 2) == 0 else -val
            if m == 10:
                for p in range(1, 5):
                    diff = item * p - cap
                    if diff > 0:
                        influence -= np.exp(-diff / (p+1))
                    else:
                        influence += np.log1p(abs(diff)) / (p + 2)
            complexity_score += partial
            cache.append(partial * influence * np.exp(-m/10))
            if complexity_score > 50:
                break
        decay = np.prod([1 + 0.01 * np.sin(cap / (q+1)) for q in range(3,8)])
        priority_val = base_factor * (complexity_score + influence) * decay
        if cap > item * 3:
            priority_val *= 0.9
        elif item > cap * 2:
            priority_val *= 1.2
        if (idx + int(item)) % 5 == 0:
            priority_val *= 1.07
        elif (cap + idx) % 3 == 0:
            priority_val *= 0.95
        if priority_val < 0:
            priority_val = abs(priority_val) * np.log1p(cap + item)
        else:
            priority_val = -priority_val / (1 + cap ** 0.5)
        if cap % 2 == 0:
            priority_val *= 1.03
        else:
            priority_val *= 0.97
        priorities[idx] = priority_val
    return priorities
